public class NestedCount {
    public static void main(String[] args) {
        int count = 0;
        for (int i = 1; i <= 3; i++) {        // outer: 3 iterations
            for (int j = 1; j <= 4; j++) {    // inner: 4 iterations EACH time
                count++;
                System.out.print("(" + i + "," + j + ") ");
            }
            System.out.println();  // newline after each outer iteration
        }
        System.out.println("Total: " + count);  // 3 × 4 = 12
    }
}

