Total: 12
*/

// For n=5:
// *
// * *
// * * *
// * * * *
// * * * * *
public class Triangle {
    public static void main(String[] args) {
        int n = 5;
        for (int i = 1; i <= n; i++) {       // row number
            for (int j = 1; j <= i; j++) {   // j goes from 1 to row number
                System.out.print("* ");
            }
            System.out.println();            // move to next row
        }
    }
}

// For n=5:
// * * * * *
