public class InvertedTriangle {
    public static void main(String[] args) {
        int n = 5;
        for (int i = n; i >= 1; i--) {       // i starts at n, goes down to 1
            for (int j = 1; j <= i; j++) {   // print i stars on row with i stars
                System.out.print("* ");
            }
            System.out.println();
        }
    }
}

