// For n=5:
//     *
//    * *
//   * * *
//  * * * *
// * * * * *
public class Pyramid {
    public static void main(String[] args) {
        int n = 5;
        for (int i = 1; i <= n; i++) {
            // Spaces: (n - i) spaces before the stars
            for (int s = 1; s <= n - i; s++) System.out.print(" ");
            // Stars: i stars
            for (int j = 1; j <= i; j++) System.out.print("* ");
            System.out.println();
        }
    }
}

// BUGGY: sum accumulates across outer iterations
public class BuggyAccumulate {
    public static void main(String[] args) {
        int n = 3;
        int sum = 0;                     // OUTSIDE outer loop
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                sum += j;                // sum keeps growing!
            }
            System.out.println("Row " + i + " sum: " + sum);
        }
        // Output: Row 1: 6, Row 2: 12, Row 3: 18  ← WRONG!
    }
}

// FIXED: sum resets each outer iteration
public class FixedAccumulate {
    public static void main(String[] args) {
        int n = 3;
        for (int i = 1; i <= n; i++) {
            int sum = 0;                 // INSIDE outer loop: resets each time
            for (int j = 1; j <= n; j++) {
                sum += j;
            }
            System.out.println("Row " + i + " sum: " + sum);
        }
        // Output: Row 1: 6, Row 2: 6, Row 3: 6  ← CORRECT
    }
}

