public class Diamond {
    public static void main(String[] args) {
        int n = 5;
        int mid = (n + 1) / 2;  // = 3 for n=5

        // Upper half (includes middle row)
        for (int i = 1; i <= mid; i++) {
            // Leading spaces
            for (int s = 0; s < mid - i; s++) System.out.print(" ");
            // Stars
            for (int j = 0; j < i; j++) System.out.print("* ");
            System.out.println();
        }

        // Lower half (mirror of upper, minus middle)
        for (int i = mid - 1; i >= 1; i--) {
            for (int s = 0; s < mid - i; s++) System.out.print(" ");
            for (int j = 0; j < i; j++) System.out.print("* ");
            System.out.println();
        }
    }
}

